"use client";

import axios from "axios";
import Script from "next/script";
import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import { Container, Row, Col, Card, Button, Form } from "react-bootstrap";
import { FaCreditCard, FaUniversity, FaArrowRight, FaCheckCircle, FaLock } from "react-icons/fa";
import { MdPayment } from "react-icons/md";
import { useRouter } from "next/navigation";
import '../../assets/styles/style.css';

declare global {
  interface Window {
    Razorpay: any;
  }
}

export default function PaymentPage() {
  const Amount = 100 * 100;
  const formattedAmount = (Amount / 100).toLocaleString('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  });
  
  const [isProcessing, setIsProcessing] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [paymentMethod, setPaymentMethod] = useState('card');
  const router = useRouter();

  useEffect(() => {
    const userData = localStorage.getItem("user");
    if (userData) {
      setUser(JSON.parse(userData));
    } else {
      router.push("/login");
    }
  }, [router]);

  const handlePayment = async () => {
    setIsProcessing(true);

    try {
      if (!user) {
        toast.error("User information not found");
        return;
      }

      const options = {
        key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
        amount: Amount,
        currency: "INR",
        name: "Bring Your Buddy",
        description: "University Application Fee",
        prefill: {
          name: user.name || "",
          email: user.email || "",
          contact: user.phone_number || "",
        },
        theme: {
          color: "#FB0200",
        },
        modal: {
          confirm_close: true,
        },
        handler: function (response) {
          handlePaymentSuccess(response);
        },
      };
      
      const rzp1 = new window.Razorpay(options);
      rzp1.on('payment.failed', function (response) {
        toast.error("Payment failed. Please try again.");
        console.log(response.error);
      });
      
      rzp1.open();
    } catch (err) {
      console.log(err);
      toast.error("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePaymentSuccess = (response) => {
    axios.post("/api/payment", { email: user.email })
      .then((res) => {
        axios.post("/api/send-documents", {
          email: user.email,
          name: user.name,
          paymentConfirmation: response.razorpay_payment_id,
          amount: Amount,
        })
          .then((res) => {
            toast.success("Payment successful! You can now check your email for further details.");
            setTimeout(() => {
              router.push("/dashboard");
            }, 2000);
          })
          .catch((err) => {
            console.log("err : ", err);
            toast.error("Payment processed but document generation failed. Please contact support.");
          });
      })
      .catch((err) => {
        console.log(err);
        toast.error("Payment processing failed. Please contact support.");
      });
  };

  return (
    <div className="auth-container payment-page">
      <Script src="https://checkout.razorpay.com/v1/checkout.js" />

      <div className="auth-card payment-card">
        <div className="row g-0">
          {/* Left Side - Image */}
          <div className="col-lg-6 d-none d-lg-block">
            <div
              className="auth-image"
              style={{
                backgroundImage: "url('/images/payment.png')",
                backgroundSize: "cover",
                backgroundPosition: "center",
              }}
            >
              <div className="overlay"></div>
              <div className="auth-image-content">
                <div className="logo-container">
                  <img src="/images/logo.png" alt="Logo" className="logo-img" />
                </div>
                <h2>Complete Your Payment</h2>
                <p>
                  Your application is almost complete! Secure your university
                  placement by completing the payment.
                </p>

                <div className="payment-benefits">
                  <div className="benefit-item fade-in">
                    <div className="benefit-icon">
                      <FaCheckCircle />
                    </div>
                    <div className="benefit-text">Get verified documents</div>
                  </div>

                  <div className="benefit-item fade-in delay-1">
                    <div className="benefit-icon">
                      <FaCheckCircle />
                    </div>
                    <div className="benefit-text">
                      Secure your university placement
                    </div>
                  </div>

                  <div className="benefit-item fade-in delay-2">
                    <div className="benefit-icon">
                      <FaCheckCircle />
                    </div>
                    <div className="benefit-text">
                      Access immigration assistance
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Right Side - Payment Form */}
          <div className="col-lg-6">
            <div className="auth-form-container">
              <div className="mobile-logo d-lg-none text-center mb-4">
                <img
                  src="/images/logo.png"
                  alt="Bring Your Buddy"
                  className="mobile-logo-img"
                />
              </div>

              <h3 className="auth-title">Payment Details</h3>
              <p className="auth-subtitle">
                Complete your payment to proceed with your application
              </p>

              <div className="payment-summary mb-4">
                <div className="payment-amount-card">
                  <div className="amount-label">Total Amount</div>
                  <div className="amount-value">{formattedAmount}</div>
                  <div className="amount-description">
                    University Application Fee
                  </div>
                </div>
              </div>

              <div className="payment-methods mb-4">
                <h5 className="payment-section-title">Payment Method</h5>

                <div className="payment-method-options">
                  <div
                    className={`payment-method-option d-flex flex-column align-items-center ${paymentMethod === "card" ? "active" : ""}`}
                    onClick={() => setPaymentMethod("card")}
                  >
                    <div className="payment-method-icon">
                      <FaCreditCard />
                    </div>
                    <div className="payment-method-label">
                      Credit/Debit Card
                    </div>
                  </div>

                  <div
                    className={`payment-method-option d-flex flex-column align-items-center ${paymentMethod === "netbanking" ? "active" : ""}`}
                    onClick={() => setPaymentMethod("netbanking")}
                  >
                    <div className="payment-method-icon">
                      <FaUniversity />
                    </div>
                    <div className="payment-method-label">Net Banking</div>
                  </div>

                  <div
                    className={`payment-method-option d-flex flex-column align-items-center ${paymentMethod === "upi" ? "active" : ""}`}
                    onClick={() => setPaymentMethod("upi")}
                  >
                    <div className="payment-method-icon">
                      <MdPayment />
                    </div>
                    <div className="payment-method-label">UPI</div>
                  </div>
                </div>
              </div>

              <div className="secure-payment-note mb-4">
                <div className="d-flex align-items-center">
                  <div className="secure-icon px-3 d-flex justify-content-center align-items-center">
                    <FaLock />
                  </div>
                  <div className="secure-text">
                    All payments are secure and encrypted. Your payment
                    information is never stored on our servers.
                  </div>
                </div>
              </div>

              <Button
                variant="primary"
                className="w-100 pay-now-btn"
                onClick={handlePayment}
                disabled={isProcessing || !user}
              >
                {isProcessing ? (
                  <>
                    <span
                      className="spinner-border spinner-border-sm me-2"
                      role="status"
                      aria-hidden="true"
                    ></span>
                    Processing...
                  </>
                ) : (
                  <div className="d-flex align-items-center justify-content-center">
                    Pay Now <FaArrowRight className="ms-2" />
                  </div>
                )}
              </Button>

              <div className="text-center mt-4">
                <Button
                  variant="link"
                  className="back-button p-0 text-danger"
                  onClick={() => router.push("/dashboard")}
                >
                  Back to Dashboard
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style jsx>{`
        .payment-page .auth-card {
          max-width: 1200px;
        }

        .payment-amount-card {
          background: linear-gradient(135deg, #003366, #00458b);
          color: white;
          border-radius: 12px;
          padding: 24px;
          text-align: center;
          box-shadow: 0 8px 20px rgba(0, 51, 102, 0.15);
          transition: all 0.3s ease;
        }

        .payment-amount-card:hover {
          transform: translateY(-5px);
          box-shadow: 0 12px 30px rgba(0, 51, 102, 0.25);
        }

        .amount-label {
          font-size: 14px;
          text-transform: uppercase;
          letter-spacing: 1px;
          opacity: 0.8;
        }

        .amount-value {
          font-size: 36px;
          font-weight: 700;
          margin: 8px 0;
        }

        .amount-description {
          font-size: 14px;
          opacity: 0.8;
        }

        .payment-section-title {
          font-size: 16px;
          font-weight: 600;
          margin-bottom: 16px;
          color: var(--secondary);
        }

        .payment-method-options {
          display: flex;
          justify-content: space-between;
          gap: 12px;
        }

        .payment-method-option {
          flex: 1;
          border: 1px solid var(--gray-light);
          background-color: var(--white);
          border-radius: 8px;
          padding: 16px 10px;
          text-align: center;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .payment-method-option:hover {
          transform: translateY(-3px);
          box-shadow: 0 5px 15px rgba(0, 0, 0, 0.05);
        }

        .payment-method-option.active {
          border-color: var(--primary);
          background-color: rgba(251, 2, 0, 0.03);
          box-shadow: 0 5px 15px rgba(251, 2, 0, 0.1);
        }

        .payment-method-icon {
          font-size: 24px;
          margin-bottom: 8px;
          color: var(--primary);
        }

        .payment-method-label {
          font-size: 14px;
          font-weight: 500;
        }

        .secure-payment-note {
          background-color: #f8f9fa;
          border-radius: 8px;
          padding: 16px;
        }

        .secure-icon {
          background-color: rgba(251, 2, 0, 0.1);
          color: var(--primary);
          width: 40px;
          height: 40px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          margin-right: 12px;
          font-size: 16px;
        }

        .secure-text {
          font-size: 14px;
          color: var(--text-muted);
        }

        .pay-now-btn {
          height: 48px;
          font-weight: 600;
          transition: all 0.3s ease;
        }

        .pay-now-btn:hover:not(:disabled) {
          transform: translateY(-2px);
          box-shadow: 0 5px 15px rgba(251, 2, 0, 0.3);
        }

        .back-button {
          color: var(--secondary);
          font-weight: 500;
          transition: all 0.3s ease;
        }

        .back-button:hover {
          transform: translateY(-1px);
          color: var(--primary);
        }

        .payment-benefits {
          margin-top: 30px;
        }

        .benefit-item {
          display: flex;
          align-items: center;
          margin-bottom: 15px;
        }

        .benefit-icon {
          color: #2ecc71;
          margin-right: 10px;
          font-size: 18px;
        }

        .benefit-text {
          font-size: 16px;
          color: white;
        }

        /* Animation classes */
        .fade-in {
          animation: fadeIn 0.8s ease forwards;
        }

        .delay-1 {
          animation-delay: 0.3s;
        }

        .delay-2 {
          animation-delay: 0.6s;
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
}